@WebService(serviceName = "PaymentService")
public class PaymentService {

    @WebMethod
    public PaymentResponse processPayment(PaymentRequest request) {
        if (request == null) {
            return new PaymentResponse(false, "INVALID_REQUEST", "Request is null", null);
        }

        if (request.getAmount() == null || request.getAmount().compareTo(BigDecimal.ZERO) <= 0) {
            return new PaymentResponse(false, "INVALID_AMOUNT", "Amount must be greater than zero", null);
        }

        if (request.getCurrency() == null || request.getCurrency().trim().isEmpty()) {
            return new PaymentResponse(false, "INVALID_CURRENCY", "Currency is required", null);
        }

        if (request.getPaymentMethod() == null || request.getPaymentMethod().trim().isEmpty()) {
            return new PaymentResponse(false, "INVALID_METHOD", "Payment method is required", null);
        }

        String transactionId = UUID.randomUUID().toString();
        return new PaymentResponse(true, "APPROVED", "Payment processed successfully", transactionId);
    }

    public static void main(String[] args) {
        String address = "http://0.0.0.0:8080/payment";
        Endpoint endpoint = Endpoint.create(new PaymentService());
        endpoint.getBinding().setHandlerChain(Collections.singletonList(new WsSecurityTimestampHandler()));
        endpoint.publish(address);
        System.out.println("PaymentService published at " + address);
    }
}

class WsSecurityTimestampHandler implements SOAPHandler<SOAPMessageContext> {

    private static final String WSSE_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd";
    private static final String WSU_NS = "http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-utility-1.0.xsd";
    private static final String TIMESTAMP_LOCAL_NAME = "Timestamp";
    private static final String CREATED_LOCAL_NAME = "Created";
    private static final String EXPIRES_LOCAL_NAME = "Expires";
    private static final long ALLOWED_CLOCK_SKEW_MILLIS = 5 * 60 * 1000L;
    private static final long REPLAY_WINDOW_MILLIS = 10 * 60 * 1000L;

    private static final ConcurrentMap<String, Long> SEEN_TIMESTAMPS = new ConcurrentHashMap<>();

    @Override
    public Set<QName> getHeaders() {
        Set<QName> headers = new HashSet<>();
        headers.add(new QName(WSSE_NS, TIMESTAMP_LOCAL_NAME));
        return headers;
    }

    @Override
    public boolean handleMessage(SOAPMessageContext context) {
        Boolean outbound = (Boolean) context.get(MessageContext.MESSAGE_OUTBOUND_PROPERTY);
        if (Boolean.TRUE.equals(outbound)) {
            return true;
        }

        try {
            SOAPMessage message = context.getMessage();
            SOAPPart part = message.getSOAPPart();
            SOAPEnvelope envelope = part.getEnvelope();
            SOAPHeader header = envelope.getHeader();

            if (header == null) {
                throw new WebServiceException("Missing SOAP header");
            }

            String created = null;
            String expires = null;

            Iterator<?> it = header.examineAllHeaderElements();
            while (it.hasNext()) {
                Object obj = it.next();
                if (obj instanceof SOAPHeaderElement) {
                    SOAPHeaderElement element = (SOAPHeaderElement) obj;
                    String localName = element.getLocalName();
                    String ns = element.getNamespaceURI();

                    if (TIMESTAMP_LOCAL_NAME.equals(localName) && WSU_NS.equals(ns)) {
                        Iterator<?> childIt = element.getChildElements();
                        while (childIt.hasNext()) {
                            Object child = childIt.next();
                            if (child instanceof SOAPElement) {
                                SOAPElement childEl = (SOAPElement) child;
                                if (CREATED_LOCAL_NAME.equals(childEl.getLocalName())) {
                                    created = childEl.getValue();
                                } else if (EXPIRES_LOCAL_NAME.equals(childEl.getLocalName())) {
                                    expires = childEl.getValue();
                                }
                            }
                        }
                    }
                }
            }

            if (created == null || expires == null) {
                throw new WebServiceException("Missing WS-Security Timestamp");
            }

            long createdMillis = parseXmlDateTime(created);
            long expiresMillis = parseXmlDateTime(expires);
            long now = System.currentTimeMillis();

            if (createdMillis - ALLOWED_CLOCK_SKEW_MILLIS > now) {
                throw new WebServiceException("Timestamp created in the future");
            }

            if (now > expiresMillis + ALLOWED_CLOCK_SKEW_MILLIS) {
                throw new WebServiceException("Timestamp expired");
            }

            String replayKey = created + "|" + expires;
            Long previous = SEEN_TIMESTAMPS.putIfAbsent(replayKey, now);
            if (previous != null) {
                throw new WebServiceException("Replay detected");
            }

            cleanupExpiredEntries(now);
            return true;
        } catch (SOAPException e) {
            throw new WebServiceException("Failed to process SOAP security header", e);
        }
    }

    private long parseXmlDateTime(String value) {
        try {
            XMLGregorianCalendar cal = DatatypeFactory.newInstance().newXMLGregorianCalendar(value);
            return cal.toGregorianCalendar().getTimeInMillis();
        } catch (DatatypeConfigurationException e) {
            throw new WebServiceException("Unable to initialize XML date parser", e);
        } catch (IllegalArgumentException e) {
            throw new WebServiceException("Invalid timestamp format: " + value, e);
        }
    }

    private void cleanupExpiredEntries(long now) {
        for (Iterator<java.util.Map.Entry<String, Long>> it = SEEN_TIMESTAMPS.entrySet().iterator(); it.hasNext(); ) {
            java.util.Map.Entry<String, Long> entry = it.next();
            if (now - entry.getValue() > REPLAY_WINDOW_MILLIS) {
                it.remove();
            }
        }
    }

    @Override
    public boolean handleFault(SOAPMessageContext context) {
        return true;
    }

    @Override
    public void close(MessageContext context) {
    }
}

